### `simple_auth.py`

This script uses a local `users.json` file to store user credentials. It salts and hashes passwords using SHA-256 (via the standard `hashlib` library) for basic security.

```python
import hashlib
import json
import os
import secrets
from getpass import getpass

class SimpleAuth:
    def __init__(self, db_file="users.json"):
        self.db_file = db_file
        self.users = self._load_users()

    def _load_users(self):
        """Load users from the JSON database file."""
        if not os.path.exists(self.db_file):
            return {}
        try:
            with open(self.db_file, "r") as f:
                return json.load(f)
        except json.JSONDecodeError:
            return {}

    def _save_users(self):
        """Save users to the JSON database file."""
        with open(self.db_file, "w") as f:
            json.dump(self.users, f, indent=4)

    def _hash_password(self, password, salt):
        """Hash a password with a salt using SHA-256."""
        return hashlib.sha256((password + salt).encode()).hexdigest()

    def register(self, username, password):
        """Register a new user."""
        if username in self.users:
            print(f"Error: User '{username}' already exists!")
            return False

        # Generate a random salt
        salt = secrets.token_hex(16)
        # Hash the password with the salt
        hashed_pw = self._hash_password(password, salt)

        self.users[username] = {
            "password": hashed_pw,
            "salt": salt
        }
        self._save_users()
        print(f"User '{username}' registered successfully!")
        return True

    def login(self, username, password):
        """Authenticate a user."""
        if username not in self.users:
            print("Error: User not found!")
            return False

        stored_data = self.users[username]
        stored_pw = stored_data["password"]
        salt = stored_data["salt"]

        # Verify the password
        if self._hash_password(password, salt) == stored_pw:
            print(f"Success: Welcome back, {username}!")
            return True
        else:
            print("Error: Invalid password!")
            return False

if __name__ == "__main__":
    auth = SimpleAuth()
    print("--- Quick Auth System ---")
    while True:
        action = input("\nEnter action (register/login/exit): ").strip().lower()
        if action == "exit":
            print("Goodbye!")
            break
        elif action in ["register", "login"]:
            username = input("Username: ").strip()
            if not username:
                print("Username cannot be empty.")
                continue
            password = getpass("Password: ")

            if action == "register":
                auth.register(username, password)
            else:
                auth.login(username, password)
        else:
            print("Invalid action. Please choose 'register', 'login', or 'exit'.")
